import hashlib
from typing import Optional


class URLShortener:
    def __init__(self):
        self._url_to_code: dict = {}
        self._code_to_url: dict = {}

    def encode(self, url: str) -> str:
        if url in self._url_to_code:
            return self._url_to_code[url]
        code = hashlib.md5(url.encode()).hexdigest()[:6]
        self._url_to_code[url] = code
        self._code_to_url[code] = url
        return code

    def decode(self, code: str) -> Optional[str]:
        return self._code_to_url.get(code)
